"use client";

import { ChangeEvent, FormEvent, useState } from "react";

interface RispostaCitata {
  avvertenza: string;
  domanda: string;
  risposta: string;
  modalita: "deterministica" | "rag-locale";
  stato: "citata" | "senza-fonti";
  metriche?: {
    coperturaCitazioni: number;
    modelloRisposta?: string;
    providerEmbedding?: string;
    recuperoFontiOnline?: {
      errore?: string;
      jobId?: string;
      stato: "non-necessario" | "non-applicabile" | "tentato" | "riuscito" | "fallito";
      urns?: string[];
    };
    retrieval: "lessicale" | "ibrido";
    richiedeRevisioneUmana: boolean;
  };
  riferimentiNormativi?: RiferimentoNormativo[];
  citazioni: Array<{
    eli: string;
    idArtefattoFonte?: string;
    label: string;
    urlFonte?: string;
  }>;
  fontiRecuperate: Array<{
    eli: string;
    id: string;
    label: string;
    metadati?: {
      idArtefattoFonte?: string;
    };
    modalita?: "lessicale" | "ibrida";
    punteggio: number;
    punteggioLessicale?: number;
    riferimentiNormativi?: RiferimentoNormativo[];
    punteggioSemantico?: number;
    testo: string;
    urlFonte?: string;
  }>;
}

interface RiferimentoNormativo {
  aEli: string;
  confidenza?: number;
  daEli: string;
  direzione: "in-uscita" | "in-entrata";
  label: string;
  statoRisoluzione: "risolto" | "esterno" | "pendente";
  targetFonte?: string;
  targetRisolto: boolean;
  targetTitolo?: string;
  targetUrlFonte?: string;
  testoMatch?: string;
  tipo: "rinvio" | "modifica" | "abrogazione" | "recepimento-ue";
}

interface FonteDettaglio {
  artefatto: {
    fonte: string;
    id: string;
    sha256?: string;
    urlFonte: string;
  };
  contenuto?: string;
  nomeFile: string;
  riferimentiNormativi?: RiferimentoNormativo[];
  unita: Array<{
    eli: string;
    etichetta: string;
    id: string;
    testo: string;
  }>;
}

interface DocumentoUploadResponse {
  documento?: {
    anteprima_testo?: string | null;
    id: string;
    nome_file: string;
  };
  errore?: string;
  stato?: string;
}

interface AnalisiDocumento {
  archiviazione: string;
  avvertenza: string;
  clausole: string[];
  nomeFile: string;
  riferimenti: Array<{
    citazioni: Array<{
      label: string;
      urlFonte?: string;
    }>;
    esito: "verificato" | "da-verificare";
    label: string;
  }>;
  riepilogo: string;
}

const esempi = [
  "Entro quando posso impugnare un licenziamento?",
  "Perché il regolamento UE è direttamente applicabile negli Stati membri?",
  "Quali norme sono collegate all'accesso civico?"
];

const modalitaComposer = [
  {
    id: "chat",
    label: "Domanda"
  },
  {
    id: "documento",
    label: "Documento"
  }
] as const;

type ModalitaComposer = (typeof modalitaComposer)[number]["id"];

export function ConsoleDomanda() {
  const [modalita, setModalita] = useState<ModalitaComposer>("chat");
  const [domanda, setDomanda] = useState("");
  const [documento, setDocumento] = useState<File | null>(null);
  const [submittedQuestion, setSubmittedQuestion] = useState<string | null>(null);
  const [response, setResponse] = useState<RispostaCitata | null>(null);
  const [analisiDocumento, setAnalisiDocumento] = useState<AnalisiDocumento | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [sourceDetail, setSourceDetail] = useState<FonteDettaglio | null>(null);
  const [sourceError, setSourceError] = useState<string | null>(null);
  const [sourcePendingId, setSourcePendingId] = useState<string | null>(null);
  const [pending, setPending] = useState(false);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();

    if (modalita === "documento") {
      await handleDocumentSubmit();
      return;
    }

    const domandaPulita = domanda.trim();

    if (!domandaPulita) {
      return;
    }

    setPending(true);
    setSubmittedQuestion(domandaPulita);
    setResponse(null);
    setAnalisiDocumento(null);
    setError(null);
    setSourceDetail(null);
    setSourceError(null);

    try {
      const apiResponse = await fetch("/api/ask", {
        method: "POST",
        headers: {
          "content-type": "application/json"
        },
        body: JSON.stringify({ domanda: domandaPulita })
      });

      if (!apiResponse.ok) {
        const payload = (await apiResponse.json().catch(() => null)) as
          | { errore?: string }
          | null;
        throw new Error(payload?.errore ?? "Non riesco a elaborare la domanda.");
      }

      setResponse((await apiResponse.json()) as RispostaCitata);
    } catch (caught) {
      setResponse(null);
      setError(caught instanceof Error ? caught.message : "Errore inatteso.");
    } finally {
      setPending(false);
    }
  }

  async function handleDocumentSubmit() {
    if (!documento) {
      setError("Scegli un contratto o un atto da analizzare.");
      return;
    }

    setPending(true);
    setSubmittedQuestion(`Analizza documento: ${documento.name}`);
    setResponse(null);
    setAnalisiDocumento(null);
    setError(null);
    setSourceDetail(null);
    setSourceError(null);

    try {
      const testoLocale = await leggiTestoDocumento(documento);
      const contenutoBase64 = await leggiFileBase64(documento);
      let archiviazione = "Documento analizzato in locale.";
      let testoAnalisi = testoLocale;

      try {
        const uploadResponse = await fetch("/api/documents", {
          body: JSON.stringify({
            caricatoDa: "chat",
            contentType: documento.type || "application/octet-stream",
            contenutoBase64,
            nomeFile: documento.name
          }),
          headers: {
            "content-type": "application/json"
          },
          method: "POST"
        });
        const payload = (await uploadResponse.json().catch(() => null)) as
          | DocumentoUploadResponse
          | null;

        if (uploadResponse.ok) {
          archiviazione = "Documento archiviato e analizzato.";
          testoAnalisi = testoAnalisi ?? payload?.documento?.anteprima_testo ?? null;
        } else if (payload?.errore) {
          archiviazione = `Documento analizzato senza archivio: ${payload.errore}`;
        }
      } catch {
        archiviazione = "Documento analizzato senza archivio: servizio archivio non disponibile.";
      }

      setAnalisiDocumento(await creaAnalisiDocumento(documento.name, testoAnalisi, archiviazione));
      setDocumento(null);
    } catch (caught) {
      setAnalisiDocumento(null);
      setError(caught instanceof Error ? caught.message : "Errore inatteso.");
    } finally {
      setPending(false);
    }
  }

  function handleDocumentChange(event: ChangeEvent<HTMLInputElement>) {
    setDocumento(event.target.files?.[0] ?? null);
    setError(null);
  }

  async function handleOpenSource(artifactId: string) {
    setSourcePendingId(artifactId);
    setSourceError(null);

    try {
      const apiResponse = await fetch(`/api/sources/${encodeURIComponent(artifactId)}`);

      if (!apiResponse.ok) {
        const payload = (await apiResponse.json().catch(() => null)) as
          | { errore?: string }
          | null;
        throw new Error(payload?.errore ?? "Fonte non disponibile.");
      }

      setSourceDetail((await apiResponse.json()) as FonteDettaglio);
    } catch (caught) {
      setSourceDetail(null);
      setSourceError(
        caught instanceof Error ? caught.message : "Errore inatteso nell'apertura fonte."
      );
    } finally {
      setSourcePendingId(null);
    }
  }

  const domandaAttiva = response?.domanda ?? submittedQuestion;
  const riferimentiNormativi = response ? raccogliRiferimentiNormativi(response) : [];

  return (
    <form className="chat-console" onSubmit={handleSubmit}>
      <div className="chat-scroll" aria-live="polite">
        <article className="message-row assistant-message">
          <div className="avatar" aria-hidden="true">
            M
          </div>
          <div className="message-bubble">
            <p className="message-kicker">Magistra OS</p>
            <p>Fai una domanda giuridica o carica un documento da analizzare.</p>
          </div>
        </article>

        {domandaAttiva ? (
          <article className="message-row user-message">
            <div className="message-bubble">
              <p>{domandaAttiva}</p>
            </div>
          </article>
        ) : null}

        {pending ? (
          <article className="message-row assistant-message">
            <div className="avatar" aria-hidden="true">
              M
            </div>
            <div className="message-bubble">
              <p className="message-kicker">
                {modalita === "documento" ? "Analisi documento" : "Ricerca fonti"}
              </p>
              <div className="typing-line">
                <span />
                <span />
                <span />
              </div>
            </div>
          </article>
        ) : null}

        {error ? (
          <article className="message-row assistant-message">
            <div className="avatar danger" aria-hidden="true">
              !
            </div>
            <div className="message-bubble error-bubble">
              <p>{error}</p>
            </div>
          </article>
        ) : null}

        {analisiDocumento ? (
          <article className="message-row assistant-message response-message">
            <div className="avatar" aria-hidden="true">
              M
            </div>
            <div className="message-bubble">
              <div className="message-header">
                <p className="message-kicker">Analisi documento</p>
                <span>{analisiDocumento.riferimenti.length} riferimenti</span>
              </div>
              <p className="answer-text">{analisiDocumento.riepilogo}</p>
              <div className="document-analysis">
                <section>
                  <h3>Clausole chiave</h3>
                  {analisiDocumento.clausole.length > 0 ? (
                    <ul>
                      {analisiDocumento.clausole.map((clausola) => (
                        <li key={clausola}>{clausola}</li>
                      ))}
                    </ul>
                  ) : (
                    <p className="hint">Nessuna clausola chiave riconoscibile dal testo.</p>
                  )}
                </section>
                <section>
                  <h3>Riferimenti normativi</h3>
                  {analisiDocumento.riferimenti.length > 0 ? (
                    <ul>
                      {analisiDocumento.riferimenti.map((riferimento) => (
                        <li key={riferimento.label}>
                          <span>{riferimento.label}</span>
                          <small>
                            {riferimento.esito === "verificato"
                              ? "verificato nelle fonti"
                              : "da verificare"}
                          </small>
                          {riferimento.citazioni.length > 0 ? (
                            <span className="document-citations">
                              {riferimento.citazioni.map((citazione) =>
                                citazione.urlFonte ? (
                                  <a
                                    href={citazione.urlFonte}
                                    key={citazione.label}
                                    rel="noreferrer"
                                    target="_blank"
                                  >
                                    {citazione.label}
                                  </a>
                                ) : (
                                  <span key={citazione.label}>{citazione.label}</span>
                                )
                              )}
                            </span>
                          ) : null}
                        </li>
                      ))}
                    </ul>
                  ) : (
                    <p className="hint">
                      Non ho trovato citazioni normative esplicite nel testo leggibile.
                    </p>
                  )}
                </section>
              </div>
              <p className="warning-text">{analisiDocumento.archiviazione}</p>
              <p className="warning-text">{analisiDocumento.avvertenza}</p>
            </div>
          </article>
        ) : null}

        {response ? (
          <article className="message-row assistant-message response-message">
            <div className="avatar" aria-hidden="true">
              M
            </div>
            <div className="message-bubble">
              <div className="message-header">
                <p className="message-kicker">
                  {response.stato === "citata"
                    ? "Risposta con fonti"
                    : "Fonti non sufficienti"}
                </p>
                <span>{response.citazioni.length} fonti</span>
              </div>
              <p className="answer-text">{response.risposta}</p>
              {response.metriche?.richiedeRevisioneUmana ? (
                <p className="review-text">
                  Verifica questa risposta con una persona qualificata prima di usarla.
                </p>
              ) : null}
              <p className="warning-text">{response.avvertenza}</p>

              {response.citazioni.length > 0 ? (
                <ol className="citation-list">
                  {response.citazioni.map((citation, index) => (
                    <li key={citation.label}>
                      <span>
                        <strong>[F{index + 1}]</strong>{" "}
                        {citation.urlFonte ? (
                          <a href={citation.urlFonte} rel="noreferrer" target="_blank">
                            {citation.label}
                          </a>
                        ) : (
                          citation.label
                        )}
                      </span>
                      {citation.idArtefattoFonte ? (
                        <button
                          className="link-button"
                          disabled={sourcePendingId === citation.idArtefattoFonte}
                          onClick={() => void handleOpenSource(citation.idArtefattoFonte!)}
                          type="button"
                        >
                          {sourcePendingId === citation.idArtefattoFonte
                            ? "Apertura..."
                            : "Leggi fonte"}
                        </button>
                      ) : null}
                    </li>
                  ))}
                </ol>
              ) : null}

              {riferimentiNormativi.length > 0 ? (
                <details className="reference-drawer" open>
                  <summary>Norme collegate</summary>
                  <ul className="reference-list" aria-label="Norme collegate">
                    {riferimentiNormativi.map((riferimento) => (
                      <li
                        className="reference-item"
                        key={`${riferimento.direzione}:${riferimento.daEli}:${riferimento.aEli}:${riferimento.tipo}`}
                      >
                        <div>
                          {riferimento.targetUrlFonte ? (
                            <a
                              href={riferimento.targetUrlFonte}
                              rel="noreferrer"
                              target="_blank"
                            >
                              {riferimento.label}
                            </a>
                          ) : (
                            <span>{riferimento.label}</span>
                          )}
                          {riferimento.testoMatch ? (
                            <p className="reference-quote">{riferimento.testoMatch}</p>
                          ) : null}
                        </div>
                        <span
                          className={`resolution-pill resolution-${riferimento.statoRisoluzione}`}
                        >
                          {labelStatoRiferimento(riferimento)}
                        </span>
                      </li>
                    ))}
                  </ul>
                </details>
              ) : null}

              {response.fontiRecuperate.length > 0 ? (
                <details className="source-drawer">
                  <summary>Passaggi usati</summary>
                  <div className="source-list" aria-label="Fonti recuperate">
                    {response.fontiRecuperate.map((fonte, index) => (
                      <section className="source-item" key={fonte.id}>
                        <div className="source-heading">
                          <span>
                            <strong>[F{index + 1}]</strong> {fonte.label}
                          </span>
                        </div>
                        <p>{fonte.testo}</p>
                        {fonte.metadati?.idArtefattoFonte ? (
                          <button
                            className="link-button inline"
                            disabled={sourcePendingId === fonte.metadati.idArtefattoFonte}
                            onClick={() =>
                              void handleOpenSource(fonte.metadati!.idArtefattoFonte!)
                            }
                            type="button"
                          >
                            Leggi fonte
                          </button>
                        ) : null}
                      </section>
                    ))}
                  </div>
                </details>
              ) : null}

              {sourceError ? <p className="error-text">{sourceError}</p> : null}

              {sourceDetail ? (
                <aside className="source-viewer" aria-label="Documento sorgente">
                  <div className="source-viewer-header">
                    <div>
                      <p className="message-kicker">Fonte consultata</p>
                      <p>{sourceDetail.nomeFile}</p>
                    </div>
                    <a
                      href={sourceDetail.artefatto.urlFonte}
                      rel="noreferrer"
                      target="_blank"
                    >
                      Apri originale
                    </a>
                  </div>
                  <div className="meta-row">
                    <span>{sourceDetail.artefatto.fonte}</span>
                    <span>{sourceDetail.unita.length} passaggi</span>
                  </div>
                  {sourceDetail.riferimentiNormativi?.length ? (
                    <ul className="reference-list compact" aria-label="Norme collegate alla fonte">
                      {sourceDetail.riferimentiNormativi.map((riferimento) => (
                        <li
                          className="reference-item"
                          key={`${riferimento.direzione}:${riferimento.daEli}:${riferimento.aEli}:${riferimento.tipo}`}
                        >
                          {riferimento.targetUrlFonte ? (
                            <a
                              href={riferimento.targetUrlFonte}
                              rel="noreferrer"
                              target="_blank"
                            >
                              {riferimento.label}
                            </a>
                          ) : (
                            <span>{riferimento.label}</span>
                          )}
                          <span
                            className={`resolution-pill resolution-${riferimento.statoRisoluzione}`}
                          >
                            {labelStatoRiferimento(riferimento)}
                          </span>
                        </li>
                      ))}
                    </ul>
                  ) : null}
                  <div className="unit-list">
                    {sourceDetail.unita.map((unit) => (
                      <section className="source-item" key={unit.id}>
                        <div className="source-heading">
                          <span>{unit.etichetta}</span>
                        </div>
                        <p>{unit.testo}</p>
                      </section>
                    ))}
                  </div>
                </aside>
              ) : null}
            </div>
          </article>
        ) : null}
      </div>

      <div className="chat-composer-wrap">
        <div className="composer-mode-row" aria-label="Modalità chat">
          {modalitaComposer.map((item) => (
            <button
              aria-pressed={modalita === item.id}
              className="mode-button"
              key={item.id}
              onClick={() => {
                setModalita(item.id);
                setError(null);
              }}
              type="button"
            >
              {item.label}
            </button>
          ))}
        </div>
        {modalita === "chat" ? (
          <>
            <div className="example-row" aria-label="Domande di esempio">
              {esempi.map((esempio) => (
                <button
                  className="example-button"
                  key={esempio}
                  onClick={() => setDomanda(esempio)}
                  type="button"
                >
                  {esempio}
                </button>
              ))}
            </div>
            <div className="chat-composer">
              <label className="visually-hidden" htmlFor="question">
                La tua domanda
              </label>
              <textarea
                className="chat-input"
                id="question"
                onChange={(event) => setDomanda(event.target.value)}
                onKeyDown={(event) => {
                  if (event.key === "Enter" && !event.shiftKey) {
                    event.preventDefault();
                    event.currentTarget.form?.requestSubmit();
                  }
                }}
                placeholder="Scrivi una domanda come la faresti a un collega..."
                rows={1}
                value={domanda}
              />
              <button
                className="send-button"
                disabled={pending || domanda.trim().length === 0}
                type="submit"
              >
                {pending ? "Cerco" : "Invia"}
              </button>
            </div>
          </>
        ) : (
          <div className="document-composer">
            <label className="file-drop">
              <span>
                {documento
                  ? documento.name
                  : "Carica un contratto, una bozza o un atto"}
              </span>
              <small>
                Riassunto, clausole chiave e controllo dei riferimenti normativi.
              </small>
              <input
                accept=".txt,.md,.markdown,.csv,.json,.xml,.html,.htm,.rtf,.pdf,.doc,.docx,application/pdf,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document,text/*"
                onChange={handleDocumentChange}
                type="file"
              />
            </label>
            <button
              className="send-button"
              disabled={pending || !documento}
              type="submit"
            >
              {pending ? "Analizzo" : "Analizza"}
            </button>
          </div>
        )}
        <p className="composer-note">
          Le risposte sono informative, citate e vanno verificate prima dell'uso.
        </p>
      </div>
    </form>
  );
}

async function creaAnalisiDocumento(
  nomeFile: string,
  testo: string | null,
  archiviazione: string
): Promise<AnalisiDocumento> {
  if (!testo) {
    return {
      archiviazione,
      avvertenza:
        "Per l'analisi automatica serve testo estraibile. Se il file è PDF o Word scansionato, converti o incolla il testo nella chat.",
      clausole: [],
      nomeFile,
      riferimenti: [],
      riepilogo:
        "Il documento è stato ricevuto, ma non contiene testo leggibile direttamente dal browser."
    };
  }

  const testoNormalizzato = normalizzaTestoDocumento(testo);
  const riferimenti = estraiRiferimentiDocumento(testoNormalizzato);

  return {
    archiviazione,
    avvertenza:
      "Analisi preliminare: non sostituisce revisione legale del documento completo.",
    clausole: estraiClausoleDocumento(testoNormalizzato),
    nomeFile,
    riferimenti: await verificaRiferimentiDocumento(riferimenti),
    riepilogo: creaRiepilogoDocumento(nomeFile, testoNormalizzato)
  };
}

async function verificaRiferimentiDocumento(
  riferimenti: string[]
): Promise<AnalisiDocumento["riferimenti"]> {
  return await Promise.all(
    riferimenti.slice(0, 5).map(async (label) => {
      try {
        const response = await fetch("/api/ask", {
          body: JSON.stringify({
            domanda: `Verifica il riferimento normativo ${label}.`
          }),
          headers: {
            "content-type": "application/json"
          },
          method: "POST"
        });

        if (!response.ok) {
          throw new Error("verifica non riuscita");
        }

        const payload = (await response.json()) as RispostaCitata;

        return {
          citazioni: payload.citazioni.map((citazione) => ({
            label: citazione.label,
            urlFonte: citazione.urlFonte
          })),
          esito: payload.citazioni.length > 0 ? "verificato" : "da-verificare",
          label
        };
      } catch {
        return {
          citazioni: [],
          esito: "da-verificare",
          label
        };
      }
    })
  );
}

async function leggiTestoDocumento(file: File): Promise<string | null> {
  if (!isDocumentoTestuale(file)) {
    return null;
  }

  const testo = await file.text();
  const pulito = normalizzaTestoDocumento(testo.replace(/\u0000/g, " "));

  return pulito.length > 0 ? pulito : null;
}

async function leggiFileBase64(file: File): Promise<string> {
  const dataUrl = await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();

    reader.onerror = () => reject(new Error("Non riesco a leggere il documento."));
    reader.onload = () => resolve(String(reader.result ?? ""));
    reader.readAsDataURL(file);
  });

  return dataUrl.split(",")[1] ?? "";
}

function isDocumentoTestuale(file: File): boolean {
  return (
    file.type.startsWith("text/") ||
    /\.(txt|md|markdown|csv|json|xml|html?|rtf)$/i.test(file.name)
  );
}

function creaRiepilogoDocumento(nomeFile: string, testo: string): string {
  const frasi = dividiInFrasi(testo);
  const primeFrasi = frasi.slice(0, 2).join(" ");

  if (primeFrasi) {
    return `${nomeFile}: ${primeFrasi}`;
  }

  return `${nomeFile}: documento leggibile acquisito, ma il testo è troppo breve per un riepilogo utile.`;
}

function estraiClausoleDocumento(testo: string): string[] {
  const categorie = [
    { label: "Oggetto", regex: /\b(oggetto|premesse|incarico|servizio|fornitura)\b/i },
    { label: "Durata e recesso", regex: /\b(durata|decorrenza|scadenza|rinnovo|recesso|disdetta)\b/i },
    { label: "Corrispettivi", regex: /\b(corrispettivo|pagamento|fattura|compenso|prezzo|penale)\b/i },
    { label: "Responsabilità", regex: /\b(responsabilita|responsabilità|manleva|indennizzo|danni)\b/i },
    { label: "Risoluzione", regex: /\b(risoluzione|inadempimento|diffida|clausola risolutiva)\b/i },
    { label: "Riservatezza e dati", regex: /\b(riservatezza|confidenziale|privacy|dati personali|gdpr)\b/i },
    { label: "Foro e legge applicabile", regex: /\b(foro|competenza|legge applicabile|controversie|arbitrato)\b/i }
  ];
  const frasi = dividiInFrasi(testo);
  const output: string[] = [];

  for (const categoria of categorie) {
    const frase = frasi.find((candidate) => categoria.regex.test(candidate));

    if (frase) {
      output.push(`${categoria.label}: ${troncaTesto(frase, 260)}`);
    }
  }

  return output.length > 0
    ? output.slice(0, 6)
    : frasi.slice(0, 3).map((frase) => troncaTesto(frase, 260));
}

function estraiRiferimentiDocumento(testo: string): string[] {
  const patterns = [
    /\bart(?:icolo)?\.?\s+[0-9]+(?:\s*[- ]?\s*(?:bis|ter|quater|quinquies))?(?:\s*,?\s*comma\s+[0-9]+)?(?:\s+(?:del|della))?\s+(?:codice civile|c\.c\.|codice penale|c\.p\.)\b/gi,
    /\bart(?:icolo)?\.?\s+[0-9]+(?:\s*[- ]?\s*(?:bis|ter|quater|quinquies))?(?:\s*,?\s*comma\s+[0-9]+)?(?:\s+(?:della|del))?\s+(?:legge|l\.)\s*(?:n\.?\s*)?[0-9]+\/[0-9]{4}\b/gi,
    /\bart(?:icolo)?\.?\s+[0-9]+(?:\s*[- ]?\s*(?:bis|ter|quater|quinquies))?(?:\s*,?\s*comma\s+[0-9]+)?(?:\s+(?:del|dello))?\s+(?:d\.?\s*lgs\.?|decreto legislativo)\s*(?:n\.?\s*)?[0-9]+\/[0-9]{4}\b/gi,
    /\b(?:legge|l\.)\s*(?:n\.?\s*)?[0-9]+\/[0-9]{4}\b/gi,
    /\b(?:d\.?\s*lgs\.?|decreto legislativo)\s*(?:n\.?\s*)?[0-9]+\/[0-9]{4}\b/gi,
    /\bregolamento\s+(?:ue|europeo)?\s*(?:n\.?\s*)?[0-9]+\/[0-9]{4}\b/gi
  ];
  const riferimenti = patterns.flatMap((pattern) => testo.match(pattern) ?? []);

  return [...new Set(riferimenti.map(normalizzaRiferimentoDocumento))].slice(0, 8);
}

function normalizzaRiferimentoDocumento(value: string): string {
  return value.replace(/\s+/g, " ").replace(/\s+\./g, ".").trim();
}

function dividiInFrasi(testo: string): string[] {
  return testo
    .split(/(?<=[.!?;])\s+/)
    .map((frase) => frase.trim())
    .filter((frase) => frase.length > 30);
}

function normalizzaTestoDocumento(testo: string): string {
  return testo.replace(/\s+/g, " ").trim().slice(0, 12000);
}

function troncaTesto(testo: string, lunghezza: number): string {
  return testo.length <= lunghezza ? testo : `${testo.slice(0, lunghezza - 1).trim()}...`;
}

function raccogliRiferimentiNormativi(response: RispostaCitata): RiferimentoNormativo[] {
  const riferimenti = [
    ...(response.riferimentiNormativi ?? []),
    ...response.fontiRecuperate.flatMap((fonte) => fonte.riferimentiNormativi ?? [])
  ];
  const seen = new Set<string>();
  const output: RiferimentoNormativo[] = [];

  for (const riferimento of riferimenti) {
    const key = `${riferimento.direzione}:${riferimento.daEli}:${riferimento.aEli}:${riferimento.tipo}`;

    if (seen.has(key)) {
      continue;
    }

    seen.add(key);
    output.push(riferimento);
  }

  return output.slice(0, 12);
}

function labelStatoRiferimento(riferimento: RiferimentoNormativo): string {
  if (riferimento.statoRisoluzione === "risolto") {
    return "nell'archivio";
  }

  if (riferimento.statoRisoluzione === "esterno") {
    return riferimento.targetFonte ?? "fonte esterna";
  }

  return "da risolvere";
}
