"use client";

import { useEffect, useState } from "react";

interface StatoIngest {
  catalogoFonti: Array<{
    dettagli?: {
      ambitoRiuso?: string;
      evidenzeRiuso?: string[];
    };
    fonte: string;
    id: string;
    licenza?: string;
    riuso: string;
    stato: string;
    statoOperativo?: {
      chunkNormativi: number;
      descrizione: string;
      sourceRuns: number;
      stato:
        | "catalogata"
        | "errore"
        | "indicizzata"
        | "non-configurata"
        | "non-indicizzata";
      ultimoAggiornamento?: string;
      ultimoErrore?: string;
    };
    tipo: string;
    url: string;
  }>;
  database: "configurato" | "non-configurato";
  job?: {
    completatoIl?: string;
    errore?: string;
    fonte: string;
    id: string;
    stato: string;
  };
  stato: string;
}

export function StatoIngest() {
  const [status, setStatus] = useState<StatoIngest | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;

    fetch("/api/ingest/status")
      .then((response) => {
        if (!response.ok) {
          throw new Error("Aggiornamento fonti non disponibile.");
        }

        return response.json() as Promise<StatoIngest>;
      })
      .then((payload) => {
        if (!cancelled) {
          setStatus(payload);
        }
      })
      .catch((caught) => {
        if (!cancelled) {
          setError(caught instanceof Error ? caught.message : "Errore inatteso.");
        }
      });

    return () => {
      cancelled = true;
    };
  }, []);

  if (error) {
    return <p className="error-text">{error}</p>;
  }

  if (!status) {
    return <p className="hint">Aggiornamento fonti in corso...</p>;
  }

  return (
    <div className="ingest-status">
      <div className="meta-row">
        <span>{status.database === "configurato" ? "Archivio pronto" : "Archivio da configurare"}</span>
        <span>{status.job?.stato === "completato" ? "Fonti aggiornate" : statoFonti(status.stato)}</span>
      </div>
      {status.job ? (
        <p className="hint">
          Ultimo aggiornamento {formatDate(status.job.completatoIl)}.
        </p>
      ) : (
        <p className="hint">Nessun aggiornamento registrato.</p>
      )}
      <div className="source-pill-list" aria-label="Catalogo fonti">
        {status.catalogoFonti.map((fonte) => (
          <span
            className="source-pill"
            key={fonte.id}
            title={descrizioneFonte(fonte)}
          >
            {fonte.fonte}
            <small>{statoFonte(fonte)}</small>
          </span>
        ))}
      </div>
    </div>
  );
}

function statoFonti(stato: string): string {
  if (stato === "ok") {
    return "Fonti pronte";
  }

  if (stato === "nessun-job") {
    return "In attesa del primo aggiornamento";
  }

  return "Verifica in corso";
}

function statoFonte(fonte: StatoIngest["catalogoFonti"][number]): string {
  const stato = fonte.statoOperativo?.stato;

  if (stato === "indicizzata") {
    return "indicizzata";
  }

  if (stato === "catalogata") {
    return "catalogata";
  }

  if (stato === "non-indicizzata") {
    return "da indicizzare";
  }

  if (stato === "errore") {
    return "errore";
  }

  if (stato === "non-configurata") {
    return "da configurare";
  }

  if (fonte.stato === "abilitata" || fonte.stato === "attiva") {
    return "catalogata";
  }

  return "in verifica";
}

function descrizioneFonte(fonte: StatoIngest["catalogoFonti"][number]): string {
  const operativo = fonte.statoOperativo;

  if (!operativo) {
    return fonte.fonte;
  }

  const dettagli = [
    operativo.descrizione,
    `Chunk: ${operativo.chunkNormativi}`,
    `Acquisizioni: ${operativo.sourceRuns}`,
    operativo.ultimoErrore ? `Errore: ${operativo.ultimoErrore}` : undefined
  ].filter(Boolean);

  return dettagli.join(" ");
}

function formatDate(value: string | undefined): string {
  if (!value) {
    return "non ancora completato";
  }

  return new Intl.DateTimeFormat("it-IT", {
    dateStyle: "medium",
    timeStyle: "short"
  }).format(new Date(value));
}
